test('user can create and complete a task', async () => {
  await login('testuser@example.com', 'password');
  await clickButton('New Task');
  await fillInput('Task title', 'Buy milk');
  await clickButton('Save');

  expect(await getText('.task-list')).toContain('Buy milk');

  await clickCheckbox('Buy milk');
  expect(await getText('.completed-tasks')).toContain('Buy milk');
});
